import axios from 'axios';
const BASE = (process.env.REACT_APP_API_BASE && process.env.REACT_APP_API_BASE !== '') ? process.env.REACT_APP_API_BASE : (typeof window !== 'undefined' ? window.location.origin : 'http://localhost:5000');
const api = axios.create({ baseURL: BASE });
export default {
  getUserLogs: ()=> api.get('/logs/me', { headers: { Authorization: 'Bearer '+localStorage.getItem('token') } }).then(r=>r.data)
};
